+/** A condition accepted by the conditional option helpers. */
+export type OptionCondition = string | OptionDependencyCondition | OptionDependency;
+
+function normalizeCondition(
+  condition: OptionCondition,
+  required: boolean,
+): OptionDependency {
+  if (typeof condition === "string") return { option: condition, required };
+  if ("option" in condition && condition.option != null) {
+    return { ...condition, required: condition.required ?? required };
+  }
+  return { ...condition, required: condition.required ?? required };
+}
+
+function conditionalOptionImpl<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T> | undefined,
+  required: boolean,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = Array.isArray(flagSpec) ? flagSpec : [flagSpec];
+  const dependsOn = normalizeCondition(condition, required);
+  return valueParser == null
+    ? option(...names, { dependsOn }) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>
+    : option(...names, valueParser, { dependsOn }) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/** Creates an option that is required unless its condition is satisfied. */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, true);
+}
+
+/** Creates an option whose visibility is controlled by a condition. */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, false);
+}
+
+/** Creates a conditional option, preserving `required` from a full condition. */
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, false);
+}
